; マップを開いた時に必ず実行されるスクリプト
[initial]

[endinitial]
;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 2, 3, 4, 5, 6, 7, 8]

;-------------------------------------------------------------------------------
*event_1
;[exp] onObjectTrigger

@notice text="On this floor, it is important not to be fooled by appearances."

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] inSearching && WAY == "w"

@notice text="There is a door, but it seems like an illusion."

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] inSearching && WAY == "e"

@notice text="There is a door, but it seems like an illusion."

[eventoff]
;-------------------------------------------------------------------------------
*event_4
;[exp] inSearching

@notice text="There is a fountain, but it seems like an illusion."

[eventoff]
;-------------------------------------------------------------------------------
*event_5
;[exp] inSearching

@notice text="There is a ladder to the upper floor, but it seems like an illusion."

[eventoff]
;-------------------------------------------------------------------------------
*event_6
;[exp] inSearching

@notice text="There is a treasure chest, but it seems to be an illusion."

[eventoff]
;-------------------------------------------------------------------------------
*event_7
;[exp] onObjectTrigger

@barrel
@damage v=&'game.curTarget.addParam("vitality", 4)'
@notice text=&'"<p>" + game.curTarget.displayName + "<w> had Vitality permanently increased by 1!"'

[eventoff]
;-------------------------------------------------------------------------------
*event_8
;[exp] ! party.isFloating() && party.lastIsMove

@btmes
[emb exp='o.火炎放射.actionMessage()']
@anireset
@call storage="anime.ks" target=*burner_trap
[r]But then I realized the flames were an illusion!
@wait time=700

[eventoff]
;-------------------------------------------------------------------------------
